25281	\section{Cohen-Macaulay rings}
25282	\label{section-CM-ring}
25283	
25284	\noindent
25285	Most of the results of this section are special cases of the results
25286	in Section \ref{section-CM}.
25287	
25288	\begin{definition}
25289	\label{definition-local-ring-CM}
25290	A Noetherian local ring $R$ is called {\it Cohen-Macaulay}
25291	if it is Cohen-Macaulay as a module over itself.
25292	\end{definition}
25293	
25294	\noindent
25295	Note that this is equivalent to requiring the existence
25296	of a $R$-regular sequence $x_1, \ldots, x_d$ of the maximal
25297	ideal such that $R/(x_1, \ldots, x_d)$ has dimension $0$.
25298	We will usually just say ``regular sequence'' and not
25299	``$R$-regular sequence''.
25300	
25301	\begin{lemma}
25302	\label{lemma-reformulate-CM}
25303	\begin{slogan}
25304	Regular sequences in Cohen-Macaulay local rings are characterized
25305	by cutting out something of the correct dimension.
25306	\end{slogan}
25307	Let $R$ be a Noetherian local Cohen-Macaulay ring with maximal
25308	ideal $\mathfrak m $. Let $x_1, \ldots, x_c \in \mathfrak m$ be
25309	elements. Then
25310	$$
25311	x_1, \ldots, x_c
25312	\text{ is a regular sequence }
25313	\Leftrightarrow
25314	\dim(R/(x_1, \ldots, x_c)) = \dim(R) - c
25315	$$
25316	If so
25317	$x_1, \ldots, x_c$ can be extended to
25318	a regular sequence of length $\dim(R)$ and each quotient
25319	$R/(x_1, \ldots, x_i)$ is a Cohen-Macaulay ring of dimension
25320	$\dim(R) - i$.
25321	\end{lemma}
25322	
25323	\begin{proof}
25324	Special case of Proposition \ref{proposition-CM-module}.
25325	\end{proof}
25326	
25327	\begin{lemma}
25328	\label{lemma-maximal-chain-CM}
25329	Let $R$ be Noetherian local.
25330	Suppose $R$ is Cohen-Macaulay of dimension $d$.
25331	Any maximal chain of ideals $\mathfrak p_0 \subset
25332	\mathfrak p_1 \subset \ldots \subset \mathfrak p_n$
25333	has length $n = d$.
25334	\end{lemma}
25335	
25336	\begin{proof}
25337	Special case of Lemma \ref{lemma-maximal-chain-maximal-CM}.
25338	\end{proof}
25339	
25340	\begin{lemma}
25341	\label{lemma-CM-dim-formula}
25342	Suppose $R$ is a Noetherian local Cohen-Macaulay ring of dimension $d$.
25343	For any prime $\mathfrak p \subset R$ we have
25344	$$
25345	\dim(R) = \dim(R_{\mathfrak p}) + \dim(R/\mathfrak p).
25346	$$
25347	\end{lemma}
25348	
25349	\begin{proof}
25350	Follows immediately from Lemma \ref{lemma-maximal-chain-CM}.
25351	(Also, this is a special case of Lemma \ref{lemma-dim-formula-maximal-CM}.)
25352	\end{proof}
25353	
25354	\begin{lemma}
25355	\label{lemma-localize-CM}
25356	Suppose $R$ is a Cohen-Macaulay local ring.
25357	For any prime $\mathfrak p \subset R$ the
25358	ring $R_{\mathfrak p}$ is Cohen-Macaulay as well.
25359	\end{lemma}
25360	
25361	\begin{proof}
25362	Special case of Lemma \ref{lemma-localize-CM-module}.
25363	\end{proof}
25364	
25365	\begin{definition}
25366	\label{definition-ring-CM}
25367	A Noetherian ring $R$ is called {\it Cohen-Macaulay} if all
25368	its local rings are Cohen-Macaulay.
25369	\end{definition}
25370	
25371	\begin{lemma}
25372	\label{lemma-CM-polynomial-algebra}
25373	Suppose $R$ is a Noetherian Cohen-Macaulay ring.
25374	Any polynomial algebra over $R$ is Cohen-Macaulay.
25375	\end{lemma}
25376	
25377	\begin{proof}
25378	Special case of Lemma \ref{lemma-maximal-CM-polynomial-algebra}.
25379	\end{proof}
25380	
25381	\begin{lemma}
25382	\label{lemma-dimension-shift}
25383	Let $R$ be a Noetherian local Cohen-Macaulay ring of dimension $d$.
25384	Let $0 \to K \to R^{\oplus n} \to M \to 0$ be an exact sequence of
25385	$R$-modules. Then either $M = 0$, or $\text{depth}(K) > \text{depth}(M)$, or
25386	$\text{depth}(K) = \text{depth}(M) = d$.
25387	\end{lemma}
25388	
25389	\begin{proof}
25390	This is a special case of Lemma \ref{lemma-depth-in-ses}.
25391	\end{proof}
25392	
25393	\begin{lemma}
25394	\label{lemma-mcm-resolution}
25395	Let $R$ be a local Noetherian Cohen-Macaulay ring of dimension $d$.
25396	Let $M$ be a finite $R$-module of depth $e$.
25397	There exists an exact complex
25398	$$
25399	0 \to K \to F_{d-e-1} \to \ldots \to F_0 \to M \to 0
25400	$$
25401	with each $F_i$ finite free and $K$ maximal Cohen-Macaulay.
25402	\end{lemma}
25403	
25404	\begin{proof}
25405	Immediate from the definition and Lemma \ref{lemma-dimension-shift}.
25406	\end{proof}
25407	
25408	\begin{lemma}
25409	\label{lemma-find-sequence-image-regular}
25410	Let $\varphi : A \to B$ be a map of local rings.
25411	Assume that $B$ is Noetherian and Cohen-Macaulay and that
25412	$\mathfrak m_B = \sqrt{\varphi(\mathfrak m_A) B}$. Then there exists
25413	a sequence of elements $f_1, \ldots, f_{\dim(B)}$ in $A$
25414	such that $\varphi(f_1), \ldots, \varphi(f_{\dim(B)})$ is a
25415	regular sequence in $B$.
25416	\end{lemma}
25417	
25418	\begin{proof}
25419	By induction on $\dim(B)$ it suffices to prove: If $\dim(B) \geq 1$, then we
25420	can find an element $f$ of $A$ which maps to a nonzerodivisor in $B$.
25421	By
25422	Lemma \ref{lemma-reformulate-CM}
25423	it suffices to find $f \in A$ whose image in $B$ is not contained in any
25424	of the finitely many minimal primes $\mathfrak q_1, \ldots, \mathfrak q_r$
25425	of $B$. By the assumption that
25426	$\mathfrak m_B = \sqrt{\varphi(\mathfrak m_A) B}$
25427	we see that $\mathfrak m_A \not \subset \varphi^{-1}(\mathfrak q_i)$.
25428	Hence we can find $f$ by
25429	Lemma \ref{lemma-silly}.
25430	\end{proof}
