25439	\section{Catenary rings}
25440	\label{section-catenary}
25441	
25442	\noindent
25443	Compare with Topology, Section \ref{topology-section-catenary-spaces}.
25444	
25445	\begin{definition}
25446	\label{definition-catenary}
25447	A ring $R$ is said to be {\it catenary} if for any pair of prime ideals
25448	$\mathfrak p \subset \mathfrak q$, there exists an integer bounding the
25449	lengths of all finite chains of prime ideals
25450	$\mathfrak p = \mathfrak p_0 \subset \mathfrak p_1 \subset \ldots \subset
25451	\mathfrak p_e = \mathfrak q$ and all maximal such chains have the same length.
25452	\end{definition}
25453	
25454	\begin{lemma}
25455	\label{lemma-catenary}
25456	A ring $R$ is catenary if and only if the topological space
25457	$\Spec(R)$ is catenary (see
25458	Topology, Definition \ref{topology-definition-catenary}).
25459	\end{lemma}
25460	
25461	\begin{proof}
25462	Immediate from the definition and the characterization of
25463	irreducible closed subsets in Lemma \ref{lemma-irreducible}.
25464	\end{proof}
25465	
25466	\noindent
25467	In general it is not the case that a finitely generated
25468	$R$-algebra is catenary if $R$ is. Thus we make the following
25469	definition.
25470	
25471	\begin{definition}
25472	\label{definition-universally-catenary}
25473	A Noetherian ring $R$ is said to be {\it universally catenary}
25474	if every $R$-algebra of finite type is catenary.
25475	\end{definition}
25476	
25477	\noindent
25478	We restrict to Noetherian rings as it is not clear
25479	this definition is the right one for non-Noetherian rings.

